    repo.git.checkout(branch)

def merge(branch):
    repo.merge(branch)

def clone(url):
    Repo.clone_from(url, '/tmp/myrepo')

def push():
    origin = repo.remote('origin')
    origin.push()

def pull():
    origin = repo.remote('origin')
    origin.pull()

def init(path):
    Repo.init(path)

def log():
    repo.git.log()

def status():
    repo.git.status()

def diff():
    repo.git.diff()

def branch(name):
    repo.git.branch(name)

